import type { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { ReactNode } from 'react';
export type TimelineIconType = 'active' | 'inactive' | 'current' | 'error';
export type AtomPosition = 'top' | 'middle' | 'bottom';
export type DirectionType = 'vertical' | 'horizontal';
export interface CollapsableTimelineProps extends Pick<TimelineProps, 'steps' | 'completed'> {
    inactive?: boolean;
}
export type TimelinePropsType = Pick<TimelineProps, 'steps' | 'completed'>;
export interface VerticalTimelineProps extends TimelinePropsType {
    activeStepIndex?: number;
}
export interface StageType {
    /**
     * Идентификатор этапа
     */
    id: string;
    /**
     * Заголовок этапа
     */
    title: ReactNode;
    /**
     * Верхний колонтитул этапа
     */
    signature?: string;
    /**
     * Основной текст этапа
     */
    text?: string;
    /**
     * Признак ошибки в этапе
     */
    error?: boolean;
    /**
     * Индивидуальная иконка этапа
     */
    iconName?: Icons;
    /**
     * Компонент кнопки.
     */
    action?: ReactNode;
}
export interface TimelineProps {
    /**
     * Идентификатор активного шага.
     */
    activeStepId?: StageType['id'];
    /**
     * Массив объектов описывающих шаги.
     * @param id: string - Идентификатор этапа.
     * @param title: string - Заголовок этапа.
     * @param signature?: string: - Верхний колонтитул этапа.
     * @param text: string: - Основной текст этапа.
     * @param error?: 'boolean' - Признак ошибки в этапе. Определяет внешний вид.
     * @param iconName?: 'Icons' - Индивидуальная иконка этапа.
     * @param action?: ReactNode - Компонент кнопки.
     */
    steps: StageType[];
    /**
     * Свойство свёрнут / развёрнут (сворачиваются пройденные блоки).
     */
    collapsed?: boolean;
    /**
     * Свойство доступности сворачивания (отображение / скрытие блока сворачивания пройденных и предстоящих этапов).
     */
    collapsable?: boolean;
    /**
     * Обработчик события клика по блоку сворачивания / разворачивания
     */
    onCollapse?: () => void;
    /**
     * Направление отображения 'vertical' | 'horizontal'
     */
    direction?: DirectionType;
    /**
     * Признак, что таймлайн полностью пройден, последний активный шаг завершён
     */
    completed?: boolean;
    /**
     * Пользовательский класс
     */
    className?: string;
}
